using ContosoUniversity.Models;
using ContosoUniversity.Services;

namespace ContosoUniversity.Tests.Services;

public class NotificationServiceTests : IDisposable
{
    private readonly NotificationService _service;

    public NotificationServiceTests()
    {
        _service = new NotificationService();
        // Drain any leftover notifications from static queue
        while (_service.ReceiveNotification() != null) { }
    }

    public void Dispose()
    {
        // Drain queue to avoid test pollution
        while (_service.ReceiveNotification() != null) { }
        _service.Dispose();
    }

    [Fact]
    public void SendNotification_Enqueues_ReceiveDequeues()
    {
        _service.SendNotification("Student", "1", EntityOperation.CREATE, "Admin");

        var notification = _service.ReceiveNotification();

        Assert.NotNull(notification);
        Assert.Equal("Student", notification.EntityType);
        Assert.Equal("1", notification.EntityId);
        Assert.Equal("CREATE", notification.Operation);
        Assert.Equal("Admin", notification.CreatedBy);
        Assert.False(notification.IsRead);
    }

    [Fact]
    public void SendNotification_WithDisplayName_GeneratesCorrectMessage()
    {
        _service.SendNotification("Course", "101", "Chemistry", EntityOperation.CREATE, "Admin");

        var notification = _service.ReceiveNotification();

        Assert.NotNull(notification);
        Assert.Contains("Chemistry", notification.Message);
        Assert.Contains("created", notification.Message);
    }

    [Fact]
    public void SendNotification_WithoutDisplayName_UsesIdInMessage()
    {
        _service.SendNotification("Student", "42", EntityOperation.UPDATE);

        var notification = _service.ReceiveNotification();

        Assert.NotNull(notification);
        Assert.Contains("42", notification.Message);
        Assert.Contains("updated", notification.Message);
    }

    [Theory]
    [InlineData(EntityOperation.CREATE, "created")]
    [InlineData(EntityOperation.UPDATE, "updated")]
    [InlineData(EntityOperation.DELETE, "deleted")]
    public void SendNotification_OperationTypes_GenerateCorrectMessages(EntityOperation operation, string expectedVerb)
    {
        _service.SendNotification("Dept", "1", "Math", operation, "User");

        var notification = _service.ReceiveNotification();

        Assert.NotNull(notification);
        Assert.Contains(expectedVerb, notification.Message);
    }

    [Fact]
    public void SendNotification_NullUserName_DefaultsToSystem()
    {
        _service.SendNotification("Student", "1", EntityOperation.CREATE, null);

        var notification = _service.ReceiveNotification();

        Assert.NotNull(notification);
        Assert.Equal("System", notification.CreatedBy);
    }

    [Fact]
    public void ReceiveNotification_EmptyQueue_ReturnsNull()
    {
        var notification = _service.ReceiveNotification();

        Assert.Null(notification);
    }

    [Fact]
    public void SendNotification_MultipleMessages_ReceiveInOrder()
    {
        _service.SendNotification("A", "1", EntityOperation.CREATE);
        _service.SendNotification("B", "2", EntityOperation.UPDATE);
        _service.SendNotification("C", "3", EntityOperation.DELETE);

        var n1 = _service.ReceiveNotification();
        var n2 = _service.ReceiveNotification();
        var n3 = _service.ReceiveNotification();

        Assert.Equal("A", n1!.EntityType);
        Assert.Equal("B", n2!.EntityType);
        Assert.Equal("C", n3!.EntityType);
    }

    [Fact]
    public void MarkAsRead_DoesNotThrow()
    {
        // MarkAsRead is a no-op for in-memory implementation, ensure no exception
        var exception = Record.Exception(() => _service.MarkAsRead(999));
        Assert.Null(exception);
    }

    [Fact]
    public void SendNotification_OverloadWithoutDisplayName_Works()
    {
        _service.SendNotification("Instructor", "5", EntityOperation.DELETE, "Admin");

        var notification = _service.ReceiveNotification();

        Assert.NotNull(notification);
        Assert.Equal("Instructor", notification.EntityType);
        Assert.Contains("deleted", notification.Message);
    }

    [Fact]
    public void Dispose_DoesNotThrow()
    {
        var service = new NotificationService();
        var exception = Record.Exception(() => service.Dispose());
        Assert.Null(exception);
    }
}

namespace ContosoUniversity.Tests;

public class PaginatedListTests
{
    private IQueryable<int> GetItems(int count) =>
        Enumerable.Range(1, count).AsQueryable();

    [Fact]
    public void Create_FirstPage_ReturnsCorrectItems()
    {
        var source = GetItems(25);

        var result = PaginatedList<int>.Create(source, 1, 10);

        Assert.Equal(10, result.Count);
        Assert.Equal(1, result.PageIndex);
        Assert.Equal(3, result.TotalPages);
        Assert.Equal(1, result[0]);
    }

    [Fact]
    public void Create_LastPage_ReturnsRemainingItems()
    {
        var source = GetItems(25);

        var result = PaginatedList<int>.Create(source, 3, 10);

        Assert.Equal(5, result.Count);
        Assert.Equal(3, result.PageIndex);
        Assert.Equal(21, result[0]);
    }

    [Fact]
    public void HasPreviousPage_FirstPage_ReturnsFalse()
    {
        var result = PaginatedList<int>.Create(GetItems(20), 1, 10);

        Assert.False(result.HasPreviousPage);
    }

    [Fact]
    public void HasPreviousPage_SecondPage_ReturnsTrue()
    {
        var result = PaginatedList<int>.Create(GetItems(20), 2, 10);

        Assert.True(result.HasPreviousPage);
    }

    [Fact]
    public void HasNextPage_LastPage_ReturnsFalse()
    {
        var result = PaginatedList<int>.Create(GetItems(20), 2, 10);

        Assert.False(result.HasNextPage);
    }

    [Fact]
    public void HasNextPage_FirstPage_ReturnsTrue()
    {
        var result = PaginatedList<int>.Create(GetItems(20), 1, 10);

        Assert.True(result.HasNextPage);
    }

    [Fact]
    public void Create_EmptySource_ReturnsEmptyList()
    {
        var source = Enumerable.Empty<int>().AsQueryable();

        var result = PaginatedList<int>.Create(source, 1, 10);

        Assert.Empty(result);
        Assert.Equal(0, result.TotalPages);
    }

    [Theory]
    [InlineData(10, 10, 1)]   // exactly one page
    [InlineData(11, 10, 2)]   // just over one page
    [InlineData(1, 10, 1)]    // single item
    public void TotalPages_CalculatedCorrectly(int itemCount, int pageSize, int expectedPages)
    {
        var result = PaginatedList<int>.Create(GetItems(itemCount), 1, pageSize);

        Assert.Equal(expectedPages, result.TotalPages);
    }
}

