    {
        _context.Instructors.Add(new Instructor { ID = 200, FirstMidName = "A", LastName = "B", HireDate = DateTime.Now });
        _context.Courses.Add(new Course { CourseID = 200, Title = "X", Credits = 1, DepartmentID = 0 });
