using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests;

public class SchoolContextTests : IDisposable
{
    private readonly SchoolContext _context;

    public SchoolContextTests()
    {
        _context = TestDbContextFactory.Create();
    }

    public void Dispose()
    {
        _context.Dispose();
    }

    [Fact]
    public void CanAddAndRetrieveStudent()
    {
        var student = new Student { FirstMidName = "Test", LastName = "User", EnrollmentDate = DateTime.Now };
        _context.Students.Add(student);
        _context.SaveChanges();

        var retrieved = _context.Students.First(s => s.LastName == "User");
        Assert.Equal("Test", retrieved.FirstMidName);
    }

    [Fact]
    public void CanAddAndRetrieveCourse()
    {
        _context.Courses.Add(new Course { CourseID = 101, Title = "TestCourse", Credits = 3, DepartmentID = 0 });
        _context.SaveChanges();

        var course = _context.Courses.Find(101);
        Assert.NotNull(course);
        Assert.Equal("TestCourse", course.Title);
    }

    [Fact]
    public void CanAddAndRetrieveDepartment()
    {
        _context.Departments.Add(new Department { DepartmentID = 50, Name = "TestDept", Budget = 1000, StartDate = DateTime.Now });
        _context.SaveChanges();

        var dept = _context.Departments.Find(50);
        Assert.NotNull(dept);
        Assert.Equal("TestDept", dept.Name);
    }

    [Fact]
    public void CanAddAndRetrieveInstructor()
    {
        _context.Instructors.Add(new Instructor { FirstMidName = "Jane", LastName = "Doe", HireDate = DateTime.Now });
        _context.SaveChanges();

        var instructor = _context.Instructors.First(i => i.LastName == "Doe");
        Assert.Equal("Jane", instructor.FirstMidName);
    }

    [Fact]
    public void CourseAssignment_CompositeKey_Works()
    {
        _context.Instructors.Add(new Instructor { ID = 200, FirstMidName = "A", LastName = "B", HireDate = DateTime.Now });
        _context.Courses.Add(new Course { CourseID = 200, Title = "X", Credits = 1, DepartmentID = 0 });
        _context.SaveChanges();

        _context.CourseAssignments.Add(new CourseAssignment { InstructorID = 200, CourseID = 200 });
        _context.SaveChanges();

        var ca = _context.CourseAssignments.Find(200, 200);
        Assert.NotNull(ca);
    }

    [Fact]
    public void Enrollment_RelationshipsWork()
    {
        _context.Students.Add(new Student { ID = 300, FirstMidName = "S", LastName = "T", EnrollmentDate = DateTime.Now });
        _context.Courses.Add(new Course { CourseID = 300, Title = "C", Credits = 2, DepartmentID = 0 });
        _context.SaveChanges();

        _context.Enrollments.Add(new Enrollment { StudentID = 300, CourseID = 300, Grade = Grade.A });
        _context.SaveChanges();

        var enrollment = _context.Enrollments.Include(e => e.Student).Include(e => e.Course)
            .First(e => e.StudentID == 300);
        Assert.Equal("T", enrollment.Student.LastName);
        Assert.Equal("C", enrollment.Course.Title);
    }

    [Fact]
    public void Person_FullName_ConcatsLastAndFirst()
    {
        var student = new Student { FirstMidName = "John", LastName = "Smith", EnrollmentDate = DateTime.Now };
        Assert.Equal("Smith, John", student.FullName);
    }
}
