using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;
using Moq;

namespace ContosoUniversity.Tests.Controllers;

public class CoursesControllerTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly CoursesController _controller;
    private readonly Mock<IWebHostEnvironment> _envMock;
    private readonly Mock<ILogger<CoursesController>> _loggerMock;

    public CoursesControllerTests()
    {
        _context = TestDbContextFactory.Create();
        SeedData.SeedCourses(_context);
        _envMock = new Mock<IWebHostEnvironment>();
        _envMock.Setup(e => e.WebRootPath).Returns(Path.GetTempPath());
        _envMock.Setup(e => e.ContentRootPath).Returns(Path.GetTempPath());
        _loggerMock = new Mock<ILogger<CoursesController>>();
        _controller = new CoursesController(_context, _envMock.Object, _loggerMock.Object);
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    [Fact]
    public void Index_ReturnsViewWithCourses()
    {
        var result = _controller.Index() as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsAssignableFrom<List<Course>>(result.Model);
        Assert.Equal(2, model.Count);
    }

    [Fact]
    public void Details_ValidId_ReturnsViewWithCourse()
    {
        var result = _controller.Details(1050) as ViewResult;

        Assert.NotNull(result);
        var course = Assert.IsType<Course>(result.Model);
        Assert.Equal("Chemistry", course.Title);
    }

    [Fact]
    public void Details_NullId_ReturnsBadRequest()
    {
        var result = _controller.Details(null) as StatusCodeResult;

        Assert.NotNull(result);
        Assert.Equal(400, result.StatusCode);
    }

    [Fact]
    public void Create_Get_ReturnsViewWithNewCourse()
    {
        var result = _controller.Create() as ViewResult;

        Assert.NotNull(result);
        Assert.IsType<Course>(result.Model);
    }

    [Fact]
    public void Create_Post_ValidCourse_NoImage_RedirectsToIndex()
    {
        var course = new Course
        {
            CourseID = 9999,
            Title = "New Course",
            Credits = 3,
            DepartmentID = 1
        };

        var result = _controller.Create(course, null!) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
        Assert.Equal(3, _context.Courses.Count());
    }

    [Fact]
    public void Create_Post_InvalidModelState_ReturnsView()
    {
        _controller.ModelState.AddModelError("Title", "Required");
        var course = new Course { CourseID = 8888, Title = "", Credits = 3, DepartmentID = 1 };

        var result = _controller.Create(course, null!) as ViewResult;

        Assert.NotNull(result);
    }

    [Fact]
    public void Create_Post_InvalidFileExtension_ReturnsViewWithError()
    {
        var course = new Course { CourseID = 7777, Title = "Test", Credits = 3, DepartmentID = 1 };
        var fileMock = new Mock<IFormFile>();
        fileMock.Setup(f => f.Length).Returns(1024);
        fileMock.Setup(f => f.FileName).Returns("test.exe");

        var result = _controller.Create(course, fileMock.Object) as ViewResult;

        Assert.NotNull(result);
        Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
    }

    [Fact]
    public void Create_Post_FileTooLarge_ReturnsViewWithError()
    {
        var course = new Course { CourseID = 7776, Title = "Test", Credits = 3, DepartmentID = 1 };
        var fileMock = new Mock<IFormFile>();
        fileMock.Setup(f => f.Length).Returns(6 * 1024 * 1024); // 6MB
        fileMock.Setup(f => f.FileName).Returns("test.jpg");

        var result = _controller.Create(course, fileMock.Object) as ViewResult;

        Assert.NotNull(result);
        Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
    }

    [Fact]
    public void Create_Post_ValidImage_SavesFileAndRedirects()
    {
        var course = new Course { CourseID = 5555, Title = "WithImage", Credits = 3, DepartmentID = 1 };
        var fileMock = new Mock<IFormFile>();
        fileMock.Setup(f => f.Length).Returns(1024);
        fileMock.Setup(f => f.FileName).Returns("material.png");
        fileMock.Setup(f => f.CopyTo(It.IsAny<Stream>()));

        var result = _controller.Create(course, fileMock.Object) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
        var saved = _context.Courses.Find(5555);
        Assert.NotNull(saved);
        Assert.Contains("/Uploads/TeachingMaterials/", saved.TeachingMaterialImagePath);
    }

    [Fact]
    public void Edit_Get_ValidId_ReturnsViewWithCourse()
    {
        var result = _controller.Edit(1050) as ViewResult;

        Assert.NotNull(result);
        var course = Assert.IsType<Course>(result.Model);
        Assert.Equal("Chemistry", course.Title);
    }

    [Fact]
    public void Edit_Get_NullId_ReturnsBadRequest()
    {
        var result = _controller.Edit(null) as StatusCodeResult;

        Assert.NotNull(result);
        Assert.Equal(400, result.StatusCode);
    }

    [Fact]
    public void Edit_Get_InvalidId_ReturnsNotFound()
    {
        var result = _controller.Edit(9999) as NotFoundResult;

        Assert.NotNull(result);
    }

    [Fact]
    public void Edit_Post_ValidCourse_NoImage_RedirectsToIndex()
    {
        var course = new Course { CourseID = 1050, Title = "Chemistry Updated", Credits = 4, DepartmentID = 1 };

        // Detach tracked entity
        var existing = _context.Courses.Find(1050)!;
        _context.Entry(existing).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

        var result = _controller.Edit(course, null!) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
    }

    [Fact]
    public void Delete_Get_ValidId_ReturnsViewWithCourse()
    {
        var result = _controller.Delete(1050) as ViewResult;

        Assert.NotNull(result);
        var course = Assert.IsType<Course>(result.Model);
        Assert.Equal("Chemistry", course.Title);
    }

    [Fact]
    public void Delete_Get_NullId_ReturnsBadRequest()
    {
        var result = _controller.Delete(null) as StatusCodeResult;

        Assert.NotNull(result);
        Assert.Equal(400, result.StatusCode);
    }

    [Fact]
    public void DeleteConfirmed_ValidId_RemovesCourseAndRedirects()
    {
        var result = _controller.DeleteConfirmed(1050) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
        Assert.Single(_context.Courses);
    }
}

