using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;

namespace ContosoUniversity.Tests.Controllers;

public class DepartmentsControllerTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly DepartmentsController _controller;

    public DepartmentsControllerTests()
    {
        _context = TestDbContextFactory.Create();
        SeedData.SeedDepartments(_context);
        _controller = new DepartmentsController(_context);
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    [Fact]
    public void Index_ReturnsViewWithDepartments()
    {
        var result = _controller.Index() as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsAssignableFrom<List<Department>>(result.Model);
        Assert.Equal(2, model.Count);
    }

    [Fact]
    public void Details_ValidId_ReturnsViewWithDepartment()
    {
        var result = _controller.Details(1) as ViewResult;

        Assert.NotNull(result);
        var department = Assert.IsType<Department>(result.Model);
        Assert.Equal("English", department.Name);
    }

    [Fact]
    public void Details_NullId_ReturnsBadRequest()
    {
        var result = _controller.Details(null) as StatusCodeResult;

        Assert.NotNull(result);
        Assert.Equal(400, result.StatusCode);
    }

    [Fact]
    public void Details_InvalidId_ReturnsNotFound()
    {
        var result = _controller.Details(999) as NotFoundResult;

        Assert.NotNull(result);
    }

    [Fact]
    public void Create_Get_ReturnsView()
    {
        var result = _controller.Create() as ViewResult;

        Assert.NotNull(result);
    }

    [Fact]
    public void Create_Post_ValidDepartment_RedirectsToIndex()
    {
        var department = new Department
        {
            Name = "Science",
            Budget = 200000,
            StartDate = new DateTime(2020, 1, 1),
            InstructorID = 10
        };

        var result = _controller.Create(department) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
        Assert.Equal(3, _context.Departments.Count());
    }

    [Fact]
    public void Create_Post_InvalidModelState_ReturnsView()
    {
        _controller.ModelState.AddModelError("Name", "Required");
        var department = new Department { Name = "" };

        var result = _controller.Create(department) as ViewResult;

        Assert.NotNull(result);
    }

    [Fact]
    public void Edit_Get_ValidId_ReturnsViewWithDepartment()
    {
        var result = _controller.Edit(1) as ViewResult;

        Assert.NotNull(result);
        var department = Assert.IsType<Department>(result.Model);
        Assert.Equal("English", department.Name);
    }

    [Fact]
    public void Edit_Get_NullId_ReturnsBadRequest()
    {
        var result = _controller.Edit(null) as StatusCodeResult;

        Assert.NotNull(result);
        Assert.Equal(400, result.StatusCode);
    }

    [Fact]
    public void Edit_Get_InvalidId_ReturnsNotFound()
    {
        var result = _controller.Edit(999) as NotFoundResult;

        Assert.NotNull(result);
    }

    [Fact]
    public void Edit_Post_ValidDepartment_RedirectsToIndex()
    {
        var department = new Department
        {
            DepartmentID = 1,
            Name = "English Updated",
            Budget = 400000,
            StartDate = new DateTime(2007, 9, 1),
            InstructorID = 10
        };

        // Detach tracked entity
        var existing = _context.Departments.Find(1)!;
        _context.Entry(existing).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

        var result = _controller.Edit(department) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
    }

    [Fact]
    public void Edit_Post_InvalidModelState_ReturnsView()
    {
        _controller.ModelState.AddModelError("Name", "Required");
        var department = new Department { DepartmentID = 1, Name = "" };

        var result = _controller.Edit(department) as ViewResult;

        Assert.NotNull(result);
    }

    [Fact]
    public void Delete_Get_ValidId_ReturnsViewWithDepartment()
    {
        var result = _controller.Delete(1) as ViewResult;

        Assert.NotNull(result);
        var department = Assert.IsType<Department>(result.Model);
        Assert.Equal("English", department.Name);
    }

    [Fact]
    public void Delete_Get_NullId_ReturnsBadRequest()
    {
        var result = _controller.Delete(null) as StatusCodeResult;

        Assert.NotNull(result);
        Assert.Equal(400, result.StatusCode);
    }

    [Fact]
    public void Delete_Get_InvalidId_ReturnsNotFound()
    {
        var result = _controller.Delete(999) as NotFoundResult;

        Assert.NotNull(result);
    }

    [Fact]
    public void DeleteConfirmed_ValidId_RemovesDepartmentAndRedirects()
    {
        var result = _controller.DeleteConfirmed(1) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
        Assert.Single(_context.Departments);
    }
}

