using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;

namespace ContosoUniversity.Tests;

public class DbInitializerTests
{
    [Fact]
    public void Initialize_EmptyDatabase_SeedsData()
    {
        using var context = TestDbContextFactory.Create();

        DbInitializer.Initialize(context);

        Assert.Equal(8, context.Students.Count());
        Assert.Equal(5, context.Instructors.Count());
        Assert.Equal(4, context.Departments.Count());
        Assert.Equal(7, context.Courses.Count());
        Assert.True(context.Enrollments.Count() > 0);
        Assert.True(context.OfficeAssignments.Count() > 0);
        Assert.True(context.CourseAssignments.Count() > 0);
    }

    [Fact]
    public void Initialize_AlreadySeeded_DoesNotDuplicate()
    {
        using var context = TestDbContextFactory.Create();

        DbInitializer.Initialize(context);
        DbInitializer.Initialize(context); // second call

        Assert.Equal(8, context.Students.Count());
    }
}

